"use strict";(self.webpackChunkgeogardenclub_github_io=self.webpackChunkgeogardenclub_github_io||[]).push([[53],{1109:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"homeSidebar":[{"type":"link","label":"Motivation","href":"/docs/home/motivation","docId":"home/motivation"},{"type":"link","label":"Design Innovations","href":"/docs/home/innovations","docId":"home/innovations"},{"type":"link","label":"Related work","href":"/docs/home/related-work","docId":"home/related-work"},{"type":"link","label":"The Team","href":"/docs/home/team","docId":"home/team"},{"type":"link","label":"Mobile App Sneak Peek","href":"/docs/home/sneak-peek","docId":"home/sneak-peek"}],"developSidebar":[{"type":"link","label":"Welcome","href":"/docs/develop/","docId":"develop/index"},{"type":"link","label":"Roadmap","href":"/docs/develop/roadmap","docId":"develop/roadmap"},{"type":"link","label":"Onboarding","href":"/docs/develop/onboarding","docId":"develop/onboarding"},{"type":"category","collapsed":true,"label":"Mockup","items":[{"type":"link","label":"Design and implementation","href":"/docs/develop/mockup/design","docId":"develop/mockup/design"},{"type":"link","label":"Customer feedback","href":"/docs/develop/mockup/customer-feedback","docId":"develop/mockup/customer-feedback"},{"type":"link","label":"Entrepreneur feedback","href":"/docs/develop/mockup/entrepreneur-feedback","docId":"develop/mockup/entrepreneur-feedback"},{"type":"link","label":"ChatGPT feedback","href":"/docs/develop/mockup/chatgpt-feedback","docId":"develop/mockup/chatgpt-feedback"}],"collapsible":true},{"type":"category","label":"Release 1.0 (Beta)","collapsed":true,"items":[{"type":"link","label":"Goals","href":"/docs/develop/release-1.0/goals","docId":"develop/release-1.0/goals"},{"type":"link","label":"Installation","href":"/docs/develop/release-1.0/installation","docId":"develop/release-1.0/installation"},{"type":"link","label":"Scripts","href":"/docs/develop/release-1.0/scripts","docId":"develop/release-1.0/scripts"},{"type":"link","label":"Core Value Propositions","href":"/docs/develop/release-1.0/cvp","docId":"develop/release-1.0/cvp"},{"type":"link","label":"Deployment","href":"/docs/develop/release-1.0/deployment","docId":"develop/release-1.0/deployment"},{"type":"link","label":"Architecture","href":"/docs/develop/release-1.0/architecture","docId":"develop/release-1.0/architecture"},{"type":"link","label":"Design patterns","href":"/docs/develop/release-1.0/patterns","docId":"develop/release-1.0/patterns"},{"type":"link","label":"Coding Standards","href":"/docs/develop/release-1.0/coding-standards","docId":"develop/release-1.0/coding-standards"},{"type":"category","collapsed":true,"label":"Design Components","items":[{"type":"link","label":"Data Model","href":"/docs/develop/release-1.0/design-components/data-model","docId":"develop/release-1.0/design-components/data-model"},{"type":"link","label":"Badges","href":"/docs/develop/release-1.0/design-components/badges","docId":"develop/release-1.0/design-components/badges"},{"type":"link","label":"GGC Input Fields","href":"/docs/develop/release-1.0/design-components/input-fields","docId":"develop/release-1.0/design-components/input-fields"}],"collapsible":true}],"collapsible":true},{"type":"category","label":"Release 2.0 (Public)","collapsed":true,"items":[{"type":"link","label":"ChapterZipMap","href":"/docs/develop/release-2.0/chapterzipmap","docId":"develop/release-2.0/chapterzipmap"}],"collapsible":true}]},"docs":{"develop/index":{"id":"develop/index","title":"Welcome to the GGC Developers Guide","description":"Welcome to the Developer\'s Guide for the Geo Garden Club project.","sidebar":"developSidebar"},"develop/mockup/chatgpt-feedback":{"id":"develop/mockup/chatgpt-feedback","title":"ChatGPT feedback","description":"Just for fun, I had a conversation with ChatGPT in April, 2023 about how to design a gardening app. Much of its responses were uninsightful, but it did come up with some banging ideas for badges.","sidebar":"developSidebar"},"develop/mockup/customer-feedback":{"id":"develop/mockup/customer-feedback","title":"Customer feedback","description":"Following the Lean Startup principle of \\"validated learning\\", we performed an evaluation study of the technology innovations present in the mockup with 24 experienced gardeners during the summer and fall of 2022.  We report on the results of that study in the following 15 minute video (or 7 minutes, if you run the video at 2x speed):","sidebar":"developSidebar"},"develop/mockup/design":{"id":"develop/mockup/design","title":"Design and implementation","description":"We built a simple single page web application using React. The goal of the system was to provide an \\"executable mockup\\" to show potential customers our vision of some of the features that would be made available in our production technology.","sidebar":"developSidebar"},"develop/mockup/entrepreneur-feedback":{"id":"develop/mockup/entrepreneur-feedback","title":"Entrepreneur feedback","description":"The following sections document feedback received from entrepreneurs and high tech professionals (who are not necessarily gardeners, and thus not in our customer demographics).  Our request to these folks was to evaluate the viability of Agile/Geo Garden Club as a commercial technology venture, and to help us identify opportunities for improvement.  We got a lot of useful feedback.","sidebar":"developSidebar"},"develop/onboarding":{"id":"develop/onboarding","title":"Onboarding","description":"Welcome, new GGC Alpha Release developer!  This page provides a checklist of things required to get started developing our technology.","sidebar":"developSidebar"},"develop/release-1.0/architecture":{"id":"develop/release-1.0/architecture","title":"Architecture","description":"The GeoGardenClub app (GGC) conforms (most of the time) to the architectural approach advocated by Andreas Bizzotto which he calls the \\"Riverpod Architecture\\".  If you are not familiar with this approach, it\'s worth spending a few minutes reading through his description, which is available as a set of readings in the architecture module in my mobile application development course.","sidebar":"developSidebar"},"develop/release-1.0/coding-standards":{"id":"develop/release-1.0/coding-standards","title":"Coding Standards","description":"In GGC, coding standards are similar to design patterns, but focus on practices that reduce or avoid \\"technical debt\\".","sidebar":"developSidebar"},"develop/release-1.0/cvp":{"id":"develop/release-1.0/cvp","title":"Core Value Propositions","description":"The goal of the 1.0 (Beta) release is to provide an app to a small group that will use the app and provide us with feedback. The 1.0 release will partially test our business model by helping us evaluate its success at implementing the \\"core value propositions\\" (CVPs) for GGC.","sidebar":"developSidebar"},"develop/release-1.0/deployment":{"id":"develop/release-1.0/deployment","title":"Deployment","description":"For the GeoGardenClub project, deployment refers to the process by which a version of the GeoGardenClub app is made available on a physical device such as an Apple or Android phone or tablet.","sidebar":"developSidebar"},"develop/release-1.0/design-components/badges":{"id":"develop/release-1.0/design-components/badges","title":"Badges","description":"Goals","sidebar":"developSidebar"},"develop/release-1.0/design-components/data-model":{"id":"develop/release-1.0/design-components/data-model","title":"Data Model","description":"This page documents the data model intended to satisfy the beta release requirements.","sidebar":"developSidebar"},"develop/release-1.0/design-components/data-model-old":{"id":"develop/release-1.0/design-components/data-model-old","title":"Data Model","description":"This page documents the data model intended to satisfy the beta release requirements."},"develop/release-1.0/design-components/input-fields":{"id":"develop/release-1.0/design-components/input-fields","title":"GGC Input Fields","description":"Motivation","sidebar":"developSidebar"},"develop/release-1.0/goals":{"id":"develop/release-1.0/goals","title":"Goals","description":"Here are a proposed set of goals for the 1.0 (Beta) release. Some of these goals are motivated by Champion Building: How to successfully adopt a developer too. Although this blog post focuses on how to get developers in an organization to adopt a new tool, the recommendation seem very applicable to getting gardeners in a community to adopt GGC.","sidebar":"developSidebar"},"develop/release-1.0/installation":{"id":"develop/release-1.0/installation","title":"Installation","description":"Flutter","sidebar":"developSidebar"},"develop/release-1.0/patterns":{"id":"develop/release-1.0/patterns","title":"Design patterns","description":"In software engineering, a design pattern is a general repeatable solution to a commonly occurring problem in software design. This page documents the design patterns we use throughout the GGC code base to solve commonly occurring implementation problems.","sidebar":"developSidebar"},"develop/release-1.0/scripts":{"id":"develop/release-1.0/scripts","title":"Scripts","description":"GGC development is supported by a number of Unix shell scripts. All scripts are named starting with \\"run\\" and use snake case to separate words in the script name.","sidebar":"developSidebar"},"develop/release-2.0/chapterzipmap":{"id":"develop/release-2.0/chapterzipmap","title":"ChapterZipMap","description":"In the 2.0 release, users will be able to register with the system from any geographic area and, based on their country and postal code, be automatically placed into a GGC Chapter.","sidebar":"developSidebar"},"develop/roadmap":{"id":"develop/roadmap","title":"Roadmap","description":"This roadmap documents our plans for incremental development and release of our technology, with the goal of revenue starting in 2026. While this pace seems glacial, note that we are bootstrapping this technology ourselves without any external investment and with no paid staff. This approach gives us the benefit of being able to delay requiring users to pay for the technology until we have documentation that our technology provides proven benefits.","sidebar":"developSidebar"},"home/innovations":{"id":"home/innovations","title":"Design Innovations","description":"Geo Garden Club includes the following design innovations:","sidebar":"homeSidebar"},"home/motivation":{"id":"home/motivation","title":"Motivation","description":"Food insecurity is an important problem in the U.S. and globally.","sidebar":"homeSidebar"},"home/related-work":{"id":"home/related-work","title":"Related work","description":"Garden Planning Tools","sidebar":"homeSidebar"},"home/sneak-peek":{"id":"home/sneak-peek","title":"Mobile App Sneak Peek","description":"We are working on the alpha release of the GeoGardenClub mobile app, with an expected release date of early 2024. While the app is not yet ready for prime time, we thought it would be fun to show you some selected screen shots so you can get an idea of where we\'re heading.","sidebar":"homeSidebar"},"home/team":{"id":"home/team","title":"The Team","description":"Jenna Deane","sidebar":"homeSidebar"}}}')}}]);